// ============================================================
// NODE: Parse Incoming Twilio Call Data
// ============================================================
// Twilio sends form-encoded POST data when a call comes in.
// We extract all the useful fields here.
//
// Fields Twilio sends:
//   CallSid       - unique ID for this call
//   Caller        - caller's phone number e.g. +923001234567
//   SpeechResult  - what the caller said (after Gather)
//   step          - which step of conversation we are on
//   collected_*   - data collected in previous steps (passed via URL params)

const body = $input.first().json.body || $input.first().json;
const query = $input.first().json.query || {};

// Get step from query params (URL) — defaults to 1 (first contact)
const step = query.step || body.step || '1';

// Get speech from Twilio's Gather result
const speechResult = body.SpeechResult || '';

// Caller phone comes from Twilio automatically
const callerPhone = body.Caller || query.collected_phone || '';

// Previously collected data (passed in URL between steps)
const collectedName     = query.collected_name     || body.collected_name     || '';
const collectedPhone    = query.collected_phone    || callerPhone;
const collectedDatetime = query.collected_datetime || body.collected_datetime || '';
const collectedReason   = query.collected_reason   || body.collected_reason   || '';
const callSid           = body.CallSid || 'DUMMY-SID-123';

console.log(`[Step ${step}] Speech: "${speechResult}"`);
console.log(`Collected so far → Name: ${collectedName}, Phone: ${collectedPhone}, DateTime: ${collectedDatetime}, Reason: ${collectedReason}`);

return [{
  json: {
    step,
    speechResult,
    callSid,
    collectedName,
    collectedPhone,
    collectedDatetime,
    collectedReason
  }
}];

// ============================================================
// NODE: DUMMY AI Conversation Logic
// ============================================================
// In the REAL workflow this calls Gemini API.
// Here we simulate the AI response with simple logic
// so you can TEST the full flow without any API key.
//
// HOW TO REPLACE WITH REAL GEMINI:
//   1. Delete this node
//   2. Add a Google Gemini node
//   3. Use the prompt from the README
//   4. Connect it between 'Parse Call Data' and 'Process AI Response'

const data = $input.first().json;
const { step, speechResult, collectedName, collectedPhone, collectedDatetime, collectedReason } = data;

let aiResponse = '';
let name = collectedName;
let phone = collectedPhone;
let datetime = collectedDatetime;
let reason = collectedReason;
let isComplete = false;

// Simple keyword extraction (dummy version of what Gemini does)
// In real version, Gemini extracts these naturally from any sentence
if (speechResult) {
  // Try to detect name (Step 1 → patient usually says their name)
  if (!name && step === '1') {
    name = speechResult.trim().split(' ').slice(0, 2).join(' ');
  }
  // Try to detect date/time keywords
  if (!datetime && (speechResult.includes('Monday') || speechResult.includes('Tuesday') ||
      speechResult.includes('Wednesday') || speechResult.includes('Thursday') ||
      speechResult.includes('Friday') || speechResult.includes('tomorrow') ||
      speechResult.match(/\d+(am|pm)/i) || speechResult.match(/\d+:\d+/))) {
    datetime = speechResult.trim();
  }
  // Detect reason keywords
  if (!reason && (speechResult.toLowerCase().includes('clean') || speechResult.toLowerCase().includes('pain') ||
      speechResult.toLowerCase().includes('check') || speechResult.toLowerCase().includes('tooth') ||
      speechResult.toLowerCase().includes('ache') || speechResult.toLowerCase().includes('whiten') ||
      speechResult.toLowerCase().includes('filling') || speechResult.toLowerCase().includes('extraction'))) {
    reason = speechResult.trim();
  }
}

// Determine what to say next based on what's missing
if (step === '1' || !name) {
  aiResponse = "Hello! Thank you for calling Bright Smile Dental. I'm Casey, your virtual receptionist. May I have your full name please?";
  name = name || '';
} else if (!datetime) {
  aiResponse = `Thank you ${name}! What date and time works best for your appointment?`;
} else if (!reason) {
  aiResponse = `Got it, ${datetime}. And what is the reason for your visit today? For example, cleaning, checkup, toothache, or something else?`;
} else {
  // All data collected!
  isComplete = true;
  aiResponse = `Perfect! I have everything I need. I've booked an appointment for ${name} on ${datetime} for ${reason}. You'll receive a confirmation shortly. Thank you for calling Bright Smile Dental. Goodbye!`;
}

console.log(`[DUMMY AI] Step ${step} → isComplete: ${isComplete}`);
console.log(`[DUMMY AI] Response: ${aiResponse}`);

return [{
  json: {
    aiResponse,
    isComplete,
    name,
    phone,
    datetime,
    reason,
    callSid: data.callSid,
    nextStep: String(parseInt(step) + 1)
  }
}];

// ============================================================
// NODE: DUMMY Airtable Save
// ============================================================
// In the REAL workflow, this is an Airtable node that creates a record.
// Here we just log the data so you can see what WOULD be saved.
//
// HOW TO REPLACE WITH REAL AIRTABLE:
//   1. Delete this node
//   2. Add an Airtable node (operation: Create Record)
//   3. Set Base ID and Table Name
//   4. Map fields as shown in README
//   5. Connect it between 'Booking Complete? (TRUE)' and 'Build Confirm TwiML'

const data = $input.first().json;

// This is what gets saved to Airtable in the real version
const recordToSave = {
  'Patient Name': data.name,
  'Phone': data.phone,
  'Appointment Date & Time': data.datetime,
  'Reason for Visit': data.reason,
  'Status': 'Pending',
  'Booked At': new Date().toISOString(),
  'Call SID': data.callSid
};

console.log('========================================');
console.log('DUMMY: Would save to Airtable:');
console.log(JSON.stringify(recordToSave, null, 2));
console.log('========================================');

// Pass data forward
return [{ json: { ...data, savedRecord: recordToSave, saveSuccess: true } }];

// ============================================================
// NODE: Build Final TwiML (Booking Confirmed)
// ============================================================
// Sends the confirmation message to the caller and hangs up.
// Uses Amazon Polly voice 'Joanna' (built into Twilio, free).

const data = $('🤖 DUMMY AI Logic (Replace with Gemini)').first().json;

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Joanna" language="en-US">${data.aiResponse}</Say>
  <Pause length="1"/>
  <Hangup/>
</Response>`;

console.log('[TwiML - CONFIRM]', twiml);

return [{ json: { twiml } }];

// ============================================================
// NODE: Build Continue TwiML (Keep Conversation Going)
// ============================================================
// Sends AI response to caller and listens for their next reply.
//
// IMPORTANT: Replace YOUR-N8N-URL with your actual n8n URL!
// Example: https://my-app.up.railway.app
//
// The collected data is passed forward in URL params between steps.
// This is how n8n remembers what was said in previous steps.

const data = $('🤖 DUMMY AI Logic (Replace with Gemini)').first().json;

// ⚠️ REPLACE THIS with your actual n8n base URL
const N8N_BASE_URL = 'https://YOUR-N8N-URL';
const webhookPath = '/webhook/dental-call';

// Build action URL with collected data as query params
const params = new URLSearchParams({
  step: data.nextStep,
  collected_name: data.name || '',
  collected_phone: data.phone || '',
  collected_datetime: data.datetime || '',
  collected_reason: data.reason || ''
});

const actionUrl = `${N8N_BASE_URL}${webhookPath}?${params.toString()}`;

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Joanna" language="en-US">${data.aiResponse}</Say>
  <Gather 
    input="speech" 
    action="${actionUrl}" 
    method="POST" 
    speechTimeout="3"
    language="en-US"
    enhanced="true">
  </Gather>
  <Redirect method="POST">${actionUrl}</Redirect>
</Response>`;

console.log('[TwiML - CONTINUE]', twiml);

return [{ json: { twiml } }];
